class Solution:
  def nearestPowerOfTwo(self, n):
    if n <= 0:
      return n
    low, high = 0, n
    while low <= high:
      mid = (low + high) // 2
      if (1 << mid) <= n:
        low = mid + 1
      else:
        high = mid - 1
    return (1 << (high - 1))

if __name__ == '__main__':
  s = Solution()
  n = int(input("Enter a number: "))
  print(s.nearestPowerOfTwo(n))

