// Solution.cpp
#include <iostream>

using namespace std;

int nearestPowerOfTwo(int n) {
  if (n <= 0)
    return n;
  int low = 0, high = n;
  while (low <= high) {
    int mid = (low + high) / 2;
    if ((1 << mid) <= n)
      low = mid + 1;
    else
      high = mid - 1;
  }
  return (1 << (high - 1));
}

int main() {
  int n;
  cin >> n;
  cout << nearestPowerOfTwo(n) << endl;
  return 0;
}
